SELECT AVG(recovery_rate) AS average_recovery_rate
FROM recovery_rates
WHERE country_id = 0;

SELECT SUM(confirmed) AS total_confirmed_cases
FROM statistics_history
WHERE stat_date = '2023-09-30';

SELECT AVG(recovered_percentage) AS average_recovery_rate
FROM recovery_rates
WHERE date = '2023-10-01';

SELECT c.country_name
FROM countries c
JOIN recovery_rates rr ON c.country_id = rr.country_id
WHERE rr.recovered_percentage = (
  SELECT MAX(recovered_percentage) FROM recovery_rates
);

SELECT confirmed
FROM statistics_history
WHERE country_id = 1 AND stat_date = '2023-09-30';

SELECT country_id, date, new_cases, new_deaths, new_recovered
FROM covid_statistics
ORDER BY date DESC;

SELECT total_confirmed
FROM region_statistics
WHERE region_id = 0 AND date = '2023-10-01';

SELECT COUNT(*) 
FROM public_health_measures
WHERE date = '2023-10-01';

SELECT SUM(cases) AS total_cases_of_delta
FROM variant_tracker
WHERE variant_name = 'Delta';

SELECT recovered_percentage
FROM recovery_rates
WHERE country_id = 0 AND date = '2023-10-01';

SELECT MAX(recovery_rate) AS max_recovery_rate
FROM recovery_rates
WHERE date = '2023-10-01';
